func TestGettersRawWorkoutResponse(t *testing.T) {
	t.Run("GetWorkouts", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &RawWorkoutResponse{}
		var expected []*RawWorkout
		obj.Workouts = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetWorkouts(), "getter should return the property value")
	})

	t.Run("GetWorkouts_NilValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &RawWorkoutResponse{}
		obj.Workouts = nil

		// Act & Assert
		assert.Nil(t, obj.GetWorkouts(), "getter should return nil when property is nil")
	})

	t.Run("GetWorkouts_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *RawWorkoutResponse
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetWorkouts() // Should return zero value
	})

}

